Alias.script:
--syntax: makelabel gray nw xxx --createMapLabel(areaID, text, posx, posy, posz, fgRed, fgGreen, fgBlue, bgRed, bgGreen, bgBlue, zoom, fontSize, showOnTop, noScaling) local color = matches[2] local place = matches[3] local labeltext = matches[4] local r, g, b local fontsize = 30
local offsets = { n = {-0.5, 2.5}, s = {-0.5, -0.5}, e = {1.0, 1.0}, nw = {-2.5, 2.5}, ne = {0.5, 2.5}, sw = {-2.5, -0.5}, se = {0.5, -0.5}, }
if table.size(wotmudmapper.currentID) == 1 and offsets[place] and color_table[color] then r, g, b = unpack(color_table[color]) local areaID = getRoomArea(wotmudmapper.currentID[1]) local pos1, pos2, pos3 = getRoomCoordinates(wotmudmapper.currentID[1]) local x = offsets[place][1] local y = offsets[place][2] x = pos1 + x y = pos2 + y createMapLabel(areaID, labeltext, x, y, pos3, r, g, b, 50, 50, 50, 30, fontsize, false, false) else wotmudmapper:echo("Current room not known, or invalid color/location/text specification.\n", false, true) end

--syntax: search room descs xxx
local phrase = matches[2] local foundrooms = {}
for id, name in pairs(getRooms()) do local desc = getRoomUserData(id, "description") if string.find(desc, phrase) then table.insert(foundrooms, id) end end
if table.is_empty(foundrooms) then wotmudmapper:echo("No matches found.
", false, true) elseif table.size(foundrooms) == 1 then wotmudmapper:echo("One matching room found. Map has been centered on this room.
") for _, id in pairs(foundrooms) do centerview(id) end else wotmudmapper:echo("Multiple matches found.
", false, true) for _, id in pairs(foundrooms) do local name = getRoomName(id) local zone = getRoomUserData(id, "zone") cechoLink( f"Room ID: {id}, <ansi_cyan>room name<reset>: {name}, ", function() local id = id wotmudmapper:echo(f"Displaying room description for room ID ({id})
") local desc = getRoomUserData(id, "description") echo(f"{desc}
") end, "Click to display room description.", true ) cechoLink( f"<{wotmudmapper.configs.zonecolor}>zone<reset>: {zone}
", function() centerview(id) end, "Click to center map on room.", true ) end end

Script.script:
function wotmudmapper:set_configs() --local copies of map configs/colors and their defaults local defaults = table.deepcopy(self.defaults) or {} local configs = table.deepcopy(self.configs) or {} local default_colors = table.deepcopy(self.default_map_colors) or {} local colors = table.deepcopy(self.map_colors) or {}
--if config and color files exist on disk, load them in self:echo("Loading map configurations.\n", true) -- load stored configs from file if it exists if io.exists(f"{getMudletHomeDir()}/wotmudmapper.configs.lua") then table.load(f"{getMudletHomeDir()}/wotmudmapper.configs.lua",configs) end if io.exists(f"{getMudletHomeDir()}/wotmudmapper.map_colors.lua") then table.load(f"{getMudletHomeDir()}/wotmudmapper.map_colors.lua",colors) end self:echo("Map configurations loaded.\n", true)
-- overwrite default values with stored config values and save to disk configs = table.update(defaults, configs) self.configs = table.deepcopy(configs) table.save(f"{getMudletHomeDir()}/wotmudmapper.configs.lua", self.configs) colors = table.update(default_colors, colors) self.map_colors = table.deepcopy(colors) table.save(f"{getMudletHomeDir()}/wotmudmapper.map_colors.lua", self.map_colors) end

function wotmudmapper:show_help(cmd) if cmd then cmd = cmd:gsub(" ","_") if not self.help[cmd] then self:echo("No help file on that command.\n",false,true) return end else cmd = 1 end for w in self.help[cmd]:gmatch("(.-)\n") do local before, target, text, after = w:match("(.*)<link: (.*)>(.*)</link>(.*)") if target then cecho(before) fg("yellow") setUnderline(true) if target == "1" then echoLink(text, function() wotmudmapper:show_help() end, "View: map help", true) else echoLink(text, function() wotmudmapper:show_help(target) end, f"View: map help {target}", true) end setUnderline(false) resetFormat() if after then cecho(after) end else cecho(w) end cecho("\n") end end
--definition of wotmudmapper.help and sub-parts wotmudmapper.help = { [[ <cyan>WoTMUD Mapping Script<reset>
This script will both follow movements through currently known rooms and allow for the creation of new rooms. It requires "color complete" to be turned on in the MUD for room names to be properly captured, and "autoexits" to be turned on to be able to determine room exits. Both are necessary for the script to function properly. The script will work with or without "brief" mode turned on in the MUD, though it will be more accurate with brief mode off. You can choose to have the script hide room descriptions instead.
This script defines the necessary function so that you can speedwalk by double clicking on rooms.
Below is a brief overview of commonly used commands that this script includes. Additional information for further areas is available as well, though every command may not be described here. All commands can be found in the appropriate mapper folder under mudlet aliases.
<cyan>Common Commands:<reset> <link: 1>map help (optional subfolder name)</link> - Shows either this help file or the help file for the subfolder given (e.g. map help booleans, map help doors, etc.) <yellow>map show<reset> - Displays or hides a map window in a fixed position. Toggle off and restart mudlet in order to make the map a dockable window via the mudlet toolbar map button <yellow>map debug<reset> - Toggles debug mode, in which extra messages are shown with the intent of assisting in troubleshooting. Default: on <yellow>resetqueue<reset> - Clears the list of movement commands maintained by the script. Useful if map appears to not be following correctly, or if aliases to open doors appear to not work properly <yellow>map update<reset> - Downloads, saves, and loads the latest version of the WoTMUD_map.dat file from https://github.com/weisluke/WoTMUD <yellow>map brief<reset> - Toggle whether map script should hide or show the descriptions from rooms. Default: show
<cyan>Information subfolders:<reset> These are sub-folders containing information for more commands <link: booleans>booleans</link> - Map variables that can be toggled on/off <link: creation>creation</link> - Commands used in creating new areas and rooms <link: room_data>room data</link> - Commands used in viewing and changing room data <link: doors>doors</link> - Commands used in creating and editing doors <link: room_colors>room colors</link> - Commands used in viewing and changing room colors <link: key_variables>key variables</link> - Variables used by the script to keep track of important information <link: map_window>map window</link> - Altering the size and position of the map display <link: misc>misc</link> - Miscellaneous commands
]] }
wotmudmapper.help.booleans = [[ <cyan>Mapper Booleans<reset> These commands control configuration options that can be toggled on/off <yellow>mapping<reset> - Turn mapping mode on/off. Default: off (will reset to off when mudlet is closed) <yellow>map bothways<reset> - Toggle whether map should set one-way or two-way exits when creating new rooms. Default: on <yellow>map autojoin<reset> - Toggle whether map should auto-join exits to nearby rooms when mapping, or whether you must actually enter a room for a connection to be made. Default: off <yellow>map brief<reset> - Toggle whether map script should hide or show the descriptions from rooms. Default: show <yellow>forceroom<reset> - Force the map to create a new room when a direction is input (as opposed to potentially linking to a room that already exists). Useful when mapping in areas that have multiple rooms with the same name (e.g. Blight) <yellow>map debug<reset> - Toggles debug mode, in which extra messages are shown with the intent of assisting in troubleshooting. Default: on <yellow>map showzone<reset> - Toggle whether the map script should display or hide zone info <yellow>map offline<reset> - Toggle whether map should be turned into offline mode, enabling offline movement aliases and numpad key bindings that allow you to move around and look via single character direction/look inputs (i.e. n/e/s/w/u/d/l), or through numpad numbers. Default: off (will reset to off, and disable offline movement aliases/keys, when mudlet is closed)
]]
wotmudmapper.help.creation = [[ <cyan>Map Creation<reset> These commands are used in creating new areas and rooms <yellow>createarea areaname<reset> - Create an area with the given name <yellow>createroom areaname<reset> - Create a new room at position (0,0,0) in the given area name, creating the area as well if the name does not already exist <yellow>movetoarea areaname<reset> - Move the current room to the given areaname, if it exists <yellow>arealist<reset> - Show a list of all areas currently known, along with their ID numbers <yellow>roomlist areaname<reset> - Show a list of all known rooms in a given area, along with their ID numbers <yellow>renamearea ID newname<reset> - Rename an area with the given ID number (from the arealist command) to the new name given <yellow>deletearea areaname<reset> - Delete an area and all rooms/labels within it <yellow>deleteroom roomID<reset> - Delete a room with the given ID number <yellow>updateroomname roomID<reset> - Update the name of the given room ID with the currently stored room name <yellow>updateroomdesc roomID<reset> - Update the description of the given room ID with the currently stored description
]]
wotmudmapper.help.room_data = [[ <cyan>Room Data:<reset> These commands are used to view and edit data stored in/around rooms <yellow>listroomdata<reset> - Display data stored for the current room. This will include room description, doors, zone, and any further data you might wish to define and store. <yellow>setroomdata key value<reset> - Set user data in the current room for a key (with no spaces) and an arbitrarily long value. Example: setroomdata herb_load sunburst, setroomdata nohide yes, setroomdata nochannel true, etc. <yellow>getroomdata key<reset> - Display data stored in the current room for the given key <yellow>deleteroomdata key<reset> - Delete the data in the current room with the given key <yellow>deleteallroomdata<reset> - Delete all data stored in the current room. This WILL delete the room description and doors which could cause the map script to not function as well as you might wish <yellow>crz zonename<reset> - Change the zone of the current room to the given name <yellow>cmz zonename<reset> - Change the zone that will be assigned to newly created rooms <yellow>shiftroom direction<reset> - Shift the current room one unit in the given direction <yellow>map zonecolor color<reset> - Change the display color for room zones <yellow>makelabel color position text<reset> - Create a text label with the given color and text at the given position relative to your current room. Possible positions include: n, e, s, ne, se, sw, nw. <yellow>viewcolors<reset> - View a list of possible colors that can be specified in the makelabel command. Opens the relevant mudlet wiki page with the colors. <yellow>setmarker symbol<reset> - Create a marker in your current room with the given symbol.
]]
wotmudmapper.help.doors = [[ <cyan>Doors:<reset> These commands are related to creating and using doors stored in the map <yellow>create status door direction doorname<reset> - Create a door with the given status and name in the given direction. Possible statuses are: visible, hidden, locked (appearing as green, yellow, and red respectively on the map) Example: create hidden door n oakdoor Doors will be automatically created when seen or searched if "mapping" is turned on <yellow>deletedoor direction<reset> - Delete the door in the given direction <yellow>map doorcolor color<reset> - Change the display color for room doors
There exist aliases built in to the script to use the doors stored in the map with various door commands and directional inputs. They are structured as: a one letter shortcut for the door command + d + direction. Door commands include o(pen), c(lose), p(ick), l(ock), u(nlock), and (k)nock. Examples: cdn to close door north, pde to pick door east, lds to lock door south, etc.
The script takes into account any movement commands that are waiting to be processed, and uses them to capture the doornames from rooms that you may not currently be in. Example: If I'm in Caemlyn Central Square, I can enter: n 4e 2n w s odd, and the script will replace "odd" with "open wellstone down".
If the door script appears to be working incorrectly, it may be because there are extra commands mistakenly stored in the movement queue that did not get processed correctly. Typing "resetqueue" to clear out extra commands should fix the issue.
]]
wotmudmapper.help.room_colors = [[ <cyan>Room Colors:<reset> These commands are used to view and change the colors in rooms <yellow>colorlegend<reset> - View the color legend for the map and its rooms <yellow>crc type<reset> - Chance the color of the current room to the given type (from the colorlegend list) Example: crc Inn <yellow>cme type<reset> - Chance the color the map assigns new rooms to the given type Example: cme Wilderness
The colors listed are just the basics that I've gone with. You could add your own by editing some parts of the script, though if you have suggestions on additions to put in, or alterations to make things more clear, I'd be more than happy to consider them.
]]
wotmudmapper.help.key_variables = [[ <cyan>Key Variables:<reset> These variables are used by the script to keep track of important information <yellow>wotmudmapper.configs<reset> - Contains a number of different options that can be set to modify script behavior <yellow>wotmudmapper.currentID<reset> - Contains a list of possible roomIDs your character might be in, according to the script <yellow>wotmudmapper.roomname<reset> - Contains the name of the room your character is in, according to the script <yellow>wotmudmapper.roomdesc<reset> - Contains the description of the room your character is in, according to the script <yellow>wotmudmapper.roomexits<reset> - Contains a table of the exits of the room your character is in, according to the script <yellow>wotmudmapper.zone<reset> - Contains the zone of the room your character is in, according to the script. This is pulled from roomdata for your currentID
]]
wotmudmapper.help.map_window = [[ <cyan>Map Window<reset> <yellow>map window setting value<reset> - This command changes the given setting to the given value, detailing how the map window should appear. Possible settings are: <yellow>x<reset> - Specify the top left corner of the map window as a percentage of the screen width. Default: -37 <yellow>y<reset> - Specify the top left corner of the map window as a percentage of the screen height. Default: 0 <yellow>w<reset> - Specify the width of the map window as a positive percentage of the screen width. Default: 37 <yellow>h<reset> - Specify the height of the map window as a positive percentage of the screen height. Default: 73 <yellow>border<reset> - Specify the color of the border of the map window. Default: gray <yellow>map zoom number<reset> - Specify the zoom level of the map. Closer to 1 = more zoomed in. Default: 50 <yellow>map dock<reset> - Make the map either dock to the left or right half of the screen, or float <yellow>map show<reset> - Displays or hides a map window in a fixed position. Toggle off and restart mudlet in order to make the map a dockable window via the mudlet toolbar map button
]]
wotmudmapper.help.misc = [[ <cyan>Misc:<reset> Various other commands that may be useful <yellow>resetqueue<reset> - Clears the list of movement commands maintained by the script. Useful if map appears to not be following correctly, or if aliases to open doors appear to not work properly <yellow>findroom roomname (zone zonename)<reset> - If a unique room with the provided name exists, the map is centered on that room. Otherwise, a list of all results is given. Providing a case sensitive WoTMUD zonename (as the map script prints them beneath the exits or displays them on the map window) can be used to narrow down results <yellow>map update<reset> - Downloads, saves, and loads the latest version of the WoTMUD_map.dat file from https://github.com/weisluke/WoTMUD <yellow>showqueue<reset> - Shows the list of currently stored movement commands <yellow>map save<reset> - Saves a copy of the map to disk <yellow>map configs reset<reset> - Reset the map configuration values.
]]

--return a list of rooms --if name is nil, return every room id --otherwise, return rooms with the provided case-sensitive name function wotmudmapper:get_rooms(name) local result = {}
if name == nil then for id, name in pairs(getRooms()) do table.insert(result, id) end else for id, name in pairs(searchRoom(name, true, true)) do table.insert(result, id) end end
return result end

function wotmudmapper:set_player_location(event, room)
  self.currentID={room}
end

registerAnonymousEventHandler("sysManualLocationSetEvent", "wotmudmapper:set_player_location")
